void processData() {
  try {
    performOperation();
  } catch (const std::exception& ex) { // Compliant: caught by const reference
    std::cout << ex.what() << std::endl;
  }
}

void handleErrors() {
  try {
    riskyFunction();
  } catch (MyCustomException& e) { // Compliant: caught by reference
    e.logError();
  }
}

void multiCatch() {
  try {
    complexOperation();
  } catch (const std::runtime_error& re) { // Compliant
    handleRuntimeError(re);
  } catch (const std::exception& ex) { // Compliant
    handleGenericError(ex);
  }
}
